    /// <param name="obj">The target object.</param>
    /// <param name="handler">The handler to be called when the event is raised.</param>
    /// <typeparam name="T">The type of the target object.</typeparam>
    /// <returns>The target object reference.</returns>
    public static T OnNavigatedFromEvent<T>(this T obj, Action<T, IObservable<Avalonia.Controls.NavigatedFromEventArgs>> handler) where T : Avalonia.Controls.Page
    {
        var observable = Observable
            .FromEventPattern<System.EventHandler<Avalonia.Controls.NavigatedFromEventArgs>, Avalonia.Controls.NavigatedFromEventArgs>(
                h => obj.NavigatedFrom += h, 
                h => obj.NavigatedFrom -= h)
            .Select(x => x.EventArgs);
        handler(obj, observable);
        return obj;
    }

